### Shared Helpers (`parity-helpers.ts`)

Create helper functions that abstract running each language's linter:

```typescript
interface LintResult {
  fired: boolean;
  ruleId: string;
  message: string;
  line: number;
}

// Run ESLint on a TS code string with specific rule enabled
async function runEslintRule(code: string, ruleName: string, filename?: string): Promise<LintResult[]>;

// Run go vet with anvil-lint analyzer on a Go code string
async function runGoAnalyzer(code: string, analyzerName: string, filename?: string): Promise<LintResult[]>;

// Run Flake8 with ANV select on a Python code string
async function runFlake8Rule(code: string, anvCode: string, filename?: string): Promise<LintResult[]>;
```

Each helper:
1. Writes the code to a temporary file in the appropriate location.
2. Runs the linter with only the specific rule enabled.
3. Parses the output to extract findings.
4. Cleans up the temporary file.
5. Returns structured results.

For Go, the helper needs a valid Go module context (go.mod). Create a reusable test fixture directory with a go.mod.

For Python, the helper needs the Flake8 plugin installed. The test should skip if the plugin is not available.

### Example Test Case

```typescript
describe("RULE-01: no-log-and-continue", () => {
  const badCode = {
    typescript: `
      try { doSomething(); }
      catch (e) { console.error(e); }
    `,
    go: `
      package main
      import "log"
      func example() {
        _, err := doSomething()
        if err != nil {
          log.Println(err)
        }
      }
    `,
    python: `
      import logging
      try:
          do_something()
      except Exception as e:
          logging.error(e)
    `,
  };

  const goodCode = {
    typescript: `
      try { doSomething(); }
      catch (e) { console.error(e); throw e; }
    `,
    go: `
      package main
      import "fmt"
      func example() error {
        _, err := doSomething()
        if err != nil {
          return fmt.Errorf("failed: %w", err)
        }
        return nil
      }
    `,
    python: `
      import logging
      try:
          do_something()
      except Exception as e:
          logging.error(e)
          raise
    `,
  };

  it("fires in TypeScript", async () => {
    const results = await runEslintRule(badCode.typescript, "anvil/no-log-and-continue");
    expect(results.length).toBeGreaterThan(0);
  });

  it("fires in Go", async () => {
    const results = await runGoAnalyzer(badCode.go, "nologcontinue");
    expect(results.length).toBeGreaterThan(0);
  });

  it("fires in Python", async () => {
    const results = await runFlake8Rule(badCode.python, "ANV001");
    expect(results.length).toBeGreaterThan(0);
  });

  it("clean code passes in all languages", async () => {
    const tsResults = await runEslintRule(goodCode.typescript, "anvil/no-log-and-continue");
    const goResults = await runGoAnalyzer(goodCode.go, "nologcontinue");
    const pyResults = await runFlake8Rule(goodCode.python, "ANV001");
    expect(tsResults).toHaveLength(0);
    expect(goResults).toHaveLength(0);
    expect(pyResults).toHaveLength(0);
  });
});
```

